input.content:
@startuml
title Текущий пайплайн генерации БФТ (bft-writer) — 10 стадий

skinparam defaultFontName Helvetica
skinparam ArrowColor #33668E
skinparam ActivityBorderColor #33668E
skinparam ActivityBackgroundColor #EAF2F8
skinparam NoteBackgroundColor #FFF6D5
skinparam NoteBorderColor #C9A227

start

:/bft-value → value.md;
note right: Стадия 0. ЗАЧЕМ инвестировать\nценность ← KR/стратегия [STOP]
if (Ценность доказана?) then (нет)
  :Вернуть продукту\n(разработку не начинать);
  stop
else (да)
endif

:/bft-context-gen → bft-context-pack.md;
note right: Стадия 1. Кортексы C1–C5 + Нексусы N1–N7\n[STOP: PO ревьюит pack]

:/bft-ext-teams → external-teams-actions.md;
note right: Стадия 1.5. Карта связей\nс командами вокруг [STOP]

:/bft-problem → problem.md;
note right: Стадия 2. Диагноз As-Is/Gap,\nБЕЗ решения [STOP]

repeat
  :/bft-concept → concept.md;
  note right: Стадия 3. 2–3 концепта решения [STOP]
  :/bft-debate → вердикт в concept.md;
  note right: Стадия 4. 3 раунда,\nАдвокат Дьявола
repeat while (Концепт забракован / пивот?) is (да) not (принят)

:/bft-constraints → constraints.md;
note right: Стадия 5. Ограничения релиза Ф/Г\nrepowise + People Graph [STOP]

repeat
  :/bft-draft → <epic>.md (черновик БФТ);
  note right: Стадия 6. БТ/ПТ/ИТ/ФТ/НФТ\n+ Ограничения релиза [STOP]
  :/bft-validate → validation.md;
  note right: Стадия 7. 19 hard gates + Светофор
repeat while (Светофор 🔴 нарушен гейт?) is (да) not (🟢 / 🟡)

:/bft-deliver → публикация;
note right: Стадия 8. JIRA Эпик + 2×Confluence\n+ связи; манифест delivery.md\n[STOP: сухой прогон → ок PO]

:Done;
stop

@enduml

input.new_string:
.pill.todo{color:var(--muted)}
.pill.prog{color:var(--accent); border-color:color-mix(in srgb,var(--accent) 40%,var(--hairline))}
.pill.wait{color:#B4791F; border-color:#D9B36655; background:#FBF3DE}
.pill.acc{color:#2F7A4C; border-color:#3C8A5A55; background:#E7F5EC}
.pill.done{color:var(--muted); background:var(--accent-soft)}
.pill.high{color:#B23B3B; border-color:#B23B3B55; background:#FBE9E9}
.must{display:inline-block; font-size:10px; font-weight:700; letter-spacing:.06em; color:#B23B3B; border:1px solid #B23B3B44; border-radius:4px; padding:0 5px; margin-right:6px; vertical-align:1px}
@media (prefers-color-scheme: dark){
  .pill.wait{background:#2E2712}.pill.acc{background:#12271A}.pill.high{background:#2A1516}.must{color:#E88}
}
:root[data-theme="dark"] .pill.wait{background:#2E2712}
:root[data-theme="dark"] .pill.acc{background:#12271A}
:root[data-theme="dark"] .pill.high{background:#2A1516}
:root[data-theme="dark"] .must{color:#E88}
:root[data-theme="light"] .pill.wait{background:#FBF3DE}
:root[data-theme="light"] .pill.acc{background:#E7F5EC}
:root[data-theme="light"] .pill.high{background:#FBE9E9}
:root[data-theme="light"] .must{color:#B23B3B}
